import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/RecordingIndicators.css';

function RecordingIndicators() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [indicatorsData, setIndicatorsData] = useState([]);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    fetchRecords();
  }, []);

  const fetchRecords = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch records');
      }
      const data = await response.json();
      setIndicatorsData(data);
    } catch (error) {
      console.error('Error fetching records:', error);
      setError('Failed to load records');
    }
  };

  const handleChange = (e, recordId, field) => {
    const { value } = e.target;

    // Оновлюємо локальний стан
    setIndicatorsData(prevData => 
      prevData.map(record => 
        record.id === recordId 
          ? { ...record, [field]: value }
          : record
      )
    );
  };

  const handleBlur = async (recordId, field, value) => {
    const user_id = localStorage.getItem('user_id');

    if (!user_id || !recordId) {
      return;
    }

    try {
      // Конвертуємо значення в правильний формат
      let processedValue = value;
      if (field !== 'date' && field !== 'medicine') {
        // Зберігаємо порожній рядок як null, але дозволяємо зберігати 0
        processedValue = value === '' ? null : Number(value);
      }

      const updateResponse = await fetch(`http://localhost:5000/api/update-health-record/${recordId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          [field]: processedValue
        }),
      });

      if (!updateResponse.ok) {
        const errorData = await updateResponse.json();
        throw new Error(errorData.error || 'Failed to update record');
      }

      setSuccess('Record updated successfully');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      console.error('Error updating record:', err);
      setError(err.message || 'Failed to update record');
      setTimeout(() => setError(''), 2000);
      await fetchRecords();
    }
  };

  const handleAddNewRow = async () => {
    const currentDate = new Date().toISOString().split('T')[0];
    const emptyRecord = {
      user_id: localStorage.getItem('user_id'),
      date: currentDate,
      FEV1: '',
      FVC: '',
      PEF: '',
      respiratory_rate: '',
      pulse: '',
      cough: '',
      breathlessness: '',
      wheezing: '',
      chest_tightness: '',
      nighttime_awakenings: '',
      medicine: ''
    };

    try {
      const response = await fetch('http://localhost:5000/api/health-records', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(emptyRecord)
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to add new record');
      }

      const result = await response.json();
      setIndicatorsData([{ ...emptyRecord, id: result.id }, ...indicatorsData]);
    } catch (error) {
      console.error('Error adding new record:', error);
      alert('Failed to add new record: ' + error.message);
    }
  };

  const handleInputChange = async (id, field, value) => {
    // Create a copy of the current record
    const record = indicatorsData.find(record => record.id === id);
    if (!record) return;

    const updatedRecord = { ...record, [field]: value };

    // Format the data based on field type
    const formattedValue = (() => {
      if (field === 'date') return value;
      if (['FEV1', 'FVC', 'PEF'].includes(field)) {
        return value === '' ? '' : parseFloat(value);
      }
      if (['respiratory_rate', 'pulse', 'cough', 'breathlessness', 
           'wheezing', 'chest_tightness', 'nighttime_awakenings'].includes(field)) {
        return value === '' ? '' : parseInt(value);
      }
      return value;
    })();

    try {
      const response = await fetch(`http://localhost:5000/api/health-records/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...updatedRecord,
          [field]: formattedValue
        })
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to update record');
      }

      // Update local state only after successful API call
      setIndicatorsData(prevData =>
        prevData.map(record =>
          record.id === id ? { ...record, [field]: value } : record
        )
      );
    } catch (error) {
      console.error('Error updating record:', error);
      alert('Failed to update record: ' + error.message);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`recording-indicators-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      <div className="content">
        <h2>Recording Indicators</h2>
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}

        <div className="table-container">
          <table className="indicators-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>FEV1</th>
                <th>FVC</th>
                <th>PEF</th>
                <th>Respiratory Rate</th>
                <th>Pulse</th>
                <th>Cough</th>
                <th>Breathlessness</th>
                <th>Wheezing</th>
                <th>Chest Tightness</th>
                <th>Nighttime Awakenings</th>
                <th>Medicine</th>
              </tr>
            </thead>
            <tbody>
              {indicatorsData.map((row) => (
                <tr key={row.id}>
                  <td>
                    <input
                      type="date"
                      value={row.date ? row.date.split('T')[0] : ''}
                      onChange={(e) => handleChange(e, row.id, 'date')}
                      onBlur={(e) => handleBlur(row.id, 'date', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      value={row.FEV1 || ''}
                      onChange={(e) => handleChange(e, row.id, 'FEV1')}
                      onBlur={(e) => handleBlur(row.id, 'FEV1', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      value={row.FVC || ''}
                      onChange={(e) => handleChange(e, row.id, 'FVC')}
                      onBlur={(e) => handleBlur(row.id, 'FVC', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.PEF || ''}
                      onChange={(e) => handleChange(e, row.id, 'PEF')}
                      onBlur={(e) => handleBlur(row.id, 'PEF', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.respiratory_rate || ''}
                      onChange={(e) => handleChange(e, row.id, 'respiratory_rate')}
                      onBlur={(e) => handleBlur(row.id, 'respiratory_rate', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.pulse || ''}
                      onChange={(e) => handleChange(e, row.id, 'pulse')}
                      onBlur={(e) => handleBlur(row.id, 'pulse', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="3"
                      value={row.cough || ''}
                      onChange={(e) => handleChange(e, row.id, 'cough')}
                      onBlur={(e) => handleBlur(row.id, 'cough', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.breathlessness || ''}
                      onChange={(e) => handleChange(e, row.id, 'breathlessness')}
                      onBlur={(e) => handleBlur(row.id, 'breathlessness', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.wheezing || ''}
                      onChange={(e) => handleChange(e, row.id, 'wheezing')}
                      onBlur={(e) => handleBlur(row.id, 'wheezing', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.chest_tightness || ''}
                      onChange={(e) => handleChange(e, row.id, 'chest_tightness')}
                      onBlur={(e) => handleBlur(row.id, 'chest_tightness', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      value={row.nighttime_awakenings || ''}
                      onChange={(e) => handleChange(e, row.id, 'nighttime_awakenings')}
                      onBlur={(e) => handleBlur(row.id, 'nighttime_awakenings', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="text"
                      value={row.medicine || ''}
                      onChange={(e) => handleChange(e, row.id, 'medicine')}
                      onBlur={(e) => handleBlur(row.id, 'medicine', e.target.value)}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <button onClick={handleAddNewRow} className="add-row-button">
          Add New Row
        </button>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default RecordingIndicators;
